1	`timescale 1ns / 1ns
2	
3	`define LB_DECODE_cryomodule
4	
5	`define AUTOMATIC_decode
6	`define AUTOMATIC_map
7	`define AUTOMATIC_beam
8	`define AUTOMATIC_cavity
9	`define AUTOMATIC_llrf
10	`define AUTOMATIC_cav_mech
11	`define AUTOMATIC_tgen
12	`include "cryomodule_auto.vh"
13	
14	// Combination of LLRF controller and cavity emulator.
15	// Portable Verilog, interfaces to a host via an abstract local bus.
16	
17	// Three clock domains, with the three clocks passed to this module:
18	//   lb_clk  e.g., 125 MHz Ethernet
19	//   clk1x   ADC clock of controller, e.g., 94 MHz for LCLS-2
20	//   clk2x   double-speed clock used by cavity simulator
21	// Proper data hand-off between clock domains is handled here.
22	
23	// In an XC7A part, synthesizes to 18132 LUT, 10 RAMB36E1, 9 RAMB18E1, 51 DSP48E1
24	// Has some "issues" making reasonable timing in the clk2x domain
25	
26	// 16-bit (0 to 7fff) address map
27	// write:
28	//      0 to 3fff   LLRF controller 1, see llrf_shell.v
29	//        (use addresses in llrf_shell block of addr_map.vh,
30	//        and maybe the registers listed in fgen.v and tgen.v)
31	//   3800           Trigger changeover to next circle_buf_0
32	//   3801           Trigger changeover to next circle_buf_0
33	//   4000 to 7fff   LLRF controller 2, see llrf_shell.v
34	//        (use addresses in llrf_shell block of addr_map.vh,
35	//        and maybe the registers listed in fgen.v and tgen.v)
36	//   8000 to ffff   Simulator, see vmod1.v
37	//        (add 4000 to addresses in vmod1 block of addr_map.vh)
38	// read:
39	//  10000 to 1003f   Configuration and parameter ROM, and circle buffer ready flag
40	//        (see config_romx.v makefile target for bits [7:0]; the ready
41	//        flag is bit 8)
42	//  12000 to 121ff   Slow readout, see slow_bridge.v
43	//        (see slow_larger.list makefile target for the contents)
44	//  12200 to 123ff   Slow readout, see slow_bridge.v
45	//        (see slow_larger.list makefile target for the contents)
46	//  14000 to 15fff   Circular buffer
47	//        (16-bit signed, usually 8 channels per time step and 1024 time
48	//        steps, when ch_keep has 8 of 12 bits set)
49	//  16000 to 17fff   Circular buffer
50	//        (16-bit signed, usually 8 channels per time step and 1024 time
51	//        steps, when ch_keep has 8 of 12 bits set)
52	// Reads are generally passive; the exception is address 5fff, which
53	// signals that the reading of one buffer is complete so the double-buffer
54	// logic and flip and make the next one available.
55	
56	// `define SIMPLE_DEMO  // Used to get a 5-minute bitfile build
57	module cryomodule(
58		input clk1x,
59		input clk2x,
60		// Local Bus drives both simulator and controller
61		// Simulator is in the upper 16K, controller in the lower 16K words.
62		input lb_clk,
63		input [31:0] lb_data,
64		input [16:0] lb_addr,
65		input lb_write,  // single-cycle causes a write
66		input lb_read,
67		output [31:0] lb_out
68	);
69	`undef AUTOMATIC_self
70	
71	// Note that the following five parameters should all be in the range 0 to 255,
72	// in order to be properly read out via config_data0, below.
73	parameter circle_aw = 13; // each half of ping-pong buffer is 8K words
74	// .. but also allows for testing
75	// The next four parameters are all passed to vmod1
76	parameter mode_count = 3;  // drives generate loop in cav_elec.v
77	parameter mode_shift = 9;
78	parameter n_mech_modes = 7;
79	parameter df_scale = 9;
80	parameter cavity_count = 2;
81	parameter cavity_ln = 1;  // ceil(log2(cavity_count))
82	
83	wire [31:0] clk1x_data;
84	wire [16:0] clk1x_addr;
85	wire clk1x_write;
86	wire clk1x_clk;
87	wire [31:0] clk2x_data;
88	wire [16:0] clk2x_addr;
89	wire clk2x_write;
90	wire clk2x_clk, clk;
91	assign clk2x_clk = clk2x;
92	assign clk=clk2x;
93	wire [31:0] lb2_data[0:cavity_count];
94	wire [16:0] lb2_addr[0:cavity_count];
95	wire lb2_write[0:cavity_count];
96	
97	wire [31:0] lb1_data[0:cavity_count];
98	wire [16:0] lb1_addr[0:cavity_count];
99	wire lb1_write[0:cavity_count];
100	wire lb2_clk = clk1x;
101	`AUTOMATIC_decode
102	`AUTOMATIC_map
103	`define SAT(x,old,new) ((~|x[old:new] | &x[old:new]) ? x[new:0] : {x[old],{new{~x[old]}}})
104	`define UNIFORM(x) ((~|(x)) | &(x))  // All 0's or all 1's
105	
106	parameter n_cycles = n_mech_modes * 2;
107	parameter interp_span = 4;  // ceil(log2(n_cycles))
108	parameter sr_length = 4*8;
109	
110	`ifndef SIMPLE_DEMO
111	// Transfer local bus to clk2x domain
112	data_xdomain #(.size(32+17)) lb_to_2x(
113	.clk_in(lb_clk), .gate_in(lb_write), .data_in({lb_addr,lb_data}),
114	.clk_out(clk2x), .gate_out(clk2x_write), .data_out({clk2x_addr,clk2x_data}));
115	// Transfer local bus to clk1x domain
116	data_xdomain #(.size(32+17)) lb_to_1x(
117	.clk_in(lb_clk), .gate_in(lb_write), .data_in({lb_addr,lb_data}),
118	.clk_out(clk1x), .gate_out(clk1x_write), .data_out({clk1x_addr,clk1x_data}));
119	`endif // SIMPLE_DEMO
120	
121	// Create start pulses at configured interval
122	reg start=0;
123	reg [7:0] mech_cnt=0;
124	always @(posedge clk2x) begin
125	   mech_cnt <= mech_cnt==0 ? n_cycles-1 : mech_cnt-1;
126	   start <= mech_cnt == 0;
127	end
128	wire start_outer;
129	reg_delay #(.dw(1), .len(0))
130		start_outer_g(.clk(clk2x), .reset(1'b0), .gate(1'b1), .din(start), .dout(start_outer));
131	wire start_eig;
132	reg_delay #(.dw(1), .len(1))
133		start_eig_g(.clk(clk2x), .reset(1'b0), .gate(1'b1), .din(start), .dout(start_eig));
134	
135	// Arrays for the generate loop
136	wire signed [17+cavity_ln:0] cav_eig_drive_acc[0:cavity_count];
137	assign cav_eig_drive_acc[0]=0;
138	wire signed [17+cavity_ln:0] piezo_eig_drive_acc[0:cavity_count];
139	assign piezo_eig_drive_acc[0]=0;
140	wire signed [15:0] circle_out[0:cavity_count];
141	wire [7:0] slow_bridge_out[0:cavity_count];
142	wire [cavity_count-1:0]circle_data_ready;
143	wire [cavity_count-1:0]slow_data_ready;
144	
145	wire [7:0] clips;  // XXX decide on a way to read this out
146	wire signed [17:0] mech_x;
147	wire simple_demo_flag;
148	// decode this address by hand
149	reg [2:0] cbuf_mode=0;
150	// XXX cbuf_mode should really be generated in clk1x domain, but it doesn't
151	// actually change that often
152	//always @(posedge lb_clk) if (lb_write & (lb_addr == 554)) cbuf_mode <= lb_data;
153	always @(posedge lb_clk) if (lb_write & (lb_addr == 17'h1022a)) cbuf_mode <= lb_data;
154	
155	genvar cavity_n;
156	generate for (cavity_n=0; cavity_n < cavity_count; cavity_n=cavity_n+1) begin: cryomodule_cavity
157	   reg signed [17:0] drive2=0; reg iq2=1;  // computed later
158	   //wire [3:0] beam_timing=0;  // XXX for simulator
159	   wire signed [17:0] piezo_ctl;  // controller output
160	   wire signed [15:0] a2_field, a2_forward, a2_reflect;  // simulator output
161	
162	   reg signed [15:0] a_field=0, a_forward=0, a_reflect=0;
163	   wire signed [17:0] drive; wire iq;
164	   // Waveform data from llrf
165	   wire [19:0] mon_result;
166	   wire mon_strobe, mon_boundary;
167	   wire buf_sync; // temporarily route to llrf_shell trig
168	   reg [15:0] buf_data=0;
169	   reg buf_strobe=0, buf_bound=0;
170	`ifndef SIMPLE_DEMO
171	   // Beam timing generator
172	   // beam_timing output is limited to [0,phase_step].
173	   wire [11:0] beam_timing;
174	   (* lb_automatic, gvar="cavity_n", gcnt=2, cd="clk2x" *)
175	   beam beam  // auto(cavity_n,2) clk2x
176	     (.clk(clk2x), .ena(iq), .reset(1'b0), .pulse(beam_timing),
177	      `AUTOMATIC_beam);
178	   // Instantiate simulator in clk2x domain
179	   wire signed [17:0] cav_eig_drive;
180	   wire signed [17:0] piezo_eig_drive;
181	   // Parameter settings here should be mirrored in param.py
182	   // Instantiating the Station module here:
183	   (* lb_automatic, gvar="cavity_n", gcnt=2, cd="clk2x" *)
184	   station #(.mode_count(mode_count), .mode_shift(mode_shift), .n_mech_modes(n_mech_modes), .df_scale(df_scale)) cavity // auto(cavity_n,2) clk2x
185	     (.clk(clk2x),
186	      .beam_timing(beam_timing), .mech_x(mech_x), .cav_eig_drive(cav_eig_drive),
187	      .piezo_eig_drive(piezo_eig_drive), .start_outer(start_outer),
188	      .iq(iq2), .drive(drive2), .start(start), .piezo(piezo_ctl),
189	      .a_field(a2_field), .a_forward(a2_forward), .a_reflect(a2_reflect),
190	      // TODO: These `we_*` wires below, are taken from the decode signals that are auto generated
191	      //.we_prng_iva(we_cavity_0_prng_iva), .we_prng_ivb(we_cavity_0_prng_ivb),
192	      `AUTOMATIC_cavity
193	      );
194	
195	   assign cav_eig_drive_acc[cavity_n+1] = cav_eig_drive_acc[cavity_n] + cav_eig_drive;
196	   assign piezo_eig_drive_acc[cavity_n+1] = piezo_eig_drive_acc[cavity_n] + piezo_eig_drive;
197	
198	   // Transfer ADCs to clk1x domain
199	   always @(posedge clk1x) begin
200	      a_field <= a2_field;
201	      a_forward <= a2_forward;
202	      a_reflect <= a2_reflect;
203	   end
204	   // Instantiate circular buffer
205	   // Reading from 0xfff is magic, says we are done reading a bank
206	   wire [15:0] circle_count, circle_stat;
207	   wire circle_stop=0; // not used
208	   //wire circle_stb = lb_read & lb_addr[14:13]==2'b10;
209	   wire buf_transferred;
210	
211	   // 0x4000 to 0x5fff for cavity 0
212	   // 0x6000 to 0x7fff for cavity 1
213	   // TODO: To be modified for cavity_count > 2
214	   wire buf_read = lb_read & (lb_addr[16:14] == 3'b101) & (lb_addr[13]==cavity_n);
215	   wire buf_flip = lb_write & (lb_addr == (17'h13800 + cavity_n));  // in lb_clk domain
216	   circle_buf #(.aw(circle_aw), .auto_flip(0)) circle(
217		.iclk(clk1x),
218		.d_in(buf_data), .stb_in(buf_strobe), .boundary(buf_bound),
219		.stop(circle_stop), .buf_sync(buf_sync),
220		.buf_transferred(buf_transferred),
221		.oclk(lb_clk), .enable(circle_data_ready[cavity_n]),
222		.read_addr(lb_addr[circle_aw-1:0]), // .read_strobe(buf_read),
223		.d_out(circle_out[cavity_n]), .stb_out(buf_flip),
224		.buf_count(circle_count), .buf_stat(circle_stat));
225	
226	   // Bridge slow readout subsystem to the local bus
227	   wire slow_op, slow_invalid;
228	   reg slow_snap=0; always @(posedge clk1x) slow_snap<=buf_sync;
229	   wire [7:0] slow_out;
230	   // 0x2000 to 0x21ff for cavity 0
231	   // 0x2200 to 0x23ff for cavity 1
232	   // Should be good up to 16 cavities
233	   wire lb_slow_read = lb_read & (lb_addr[16:9] == 'b10010000 + cavity_n);
234	   slow_bridge slow_bridge(.lb_clk(lb_clk), .lb_addr(lb_addr[14:0]),
235				   .lb_read(lb_slow_read), .lb_out(slow_bridge_out[cavity_n]),
236				   .invalid(slow_invalid),
237				   .slow_clk(clk1x), .slow_op(slow_op), .slow_snap(buf_transferred),
238				   .slow_out(slow_out));
239	   assign slow_data_ready[cavity_n] = circle_data_ready[cavity_n] & ~slow_invalid;  // XXX mixes domains, simulate to make sure it's glitch-free
240	   // Make our own additions to slow shift register
241	   // equivalence circle_stat: circle_fault 1, circle_wrap 1, circle_addr 14
242	   wire [sr_length-1:0] slow_sr_data = { circle_count, circle_stat };
243	   // TODO: These `we_*` wires below, are taken from the decode signals that are auto generated
244	   wire [7:0] slow_shell_out;
245	
246	   reg [sr_length-1:0] slow_read=0;
247	   always @(posedge clk1x) if (slow_op) begin
248	      slow_read <= slow_snap ? slow_sr_data : {slow_read[sr_length-9:0],slow_shell_out};
249	   end
250	   assign slow_out = slow_read[sr_length-1:sr_length-8];
251	
252	   assign simple_demo_flag = 0;
253	   // Instantiate controller in clk domain
254	   wire ext_trig=buf_sync;
255	
256	
257	   // Timing generator, interposes on local bus
258	   wire collision, collision1;
259	
260	`define USE_TGEN
261	`ifdef USE_TGEN
262	   (* lb_automatic, gvar="cavity_n", gcnt=2, cd="lb2", cd_indexed *)
263	   tgen tgen // auto(cavity_n,2) lb2[cavity_n]
264	     (.clk(clk1x), .trig(ext_trig), .collision(collision1),
265	      .lb_data(clk1x_data), .lb_write(clk1x_write), .lb_addr(clk1x_addr),
266	      .addr_padding(1'b0),
267	      .lbo_data(lb1_data[cavity_n]), .lbo_write(lb1_write[cavity_n]), .lbo_addr(lb1_addr[cavity_n]),
268	      // TODO: This is hard-coded to the tgen_0
269	      // .delay_pc_addr_hit(`ADDR_HIT_tgen_0_delay_pc_XXX & (cavity_n == 0)),
270	      // Note: use of we_tgen_0_delay_pc_XXX triggers warnings under newad -y
271	      // since it's so tightly coupled to operation of newad.  Actually harmless.
272	      .dests_write(we_tgen_0_delay_pc_XXX & (cavity_n == 0)),
273	      `AUTOMATIC_tgen
274	      );
275	`else
276	   assign lb1_data[cavity_n] = clk1x_data;
277	   assign lb1_addr[cavity_n] = clk1x_addr;
278	   assign lb1_write[cavity_n] = clk1x_write;
279	   assign collision1 = 0;
280	`endif
281	
282	   // Function generator, interposes on local bus
283	   //`define USE_FGEN
284	`ifdef USE_FGEN
285	   fgen #(.addr_hi(0)) fgen(.clk(clk1x), .trig(ext_trig), .collision(collision),
286				    .lb_data(lb1_data[cavity_n]), .lb_write(lb1_write[cavity_n]), .lb_addr(lb1_addr[cavity_n]),
287				    .lbo_data(lb2_data[cavity_n]), .lbo_write(lb2_write[cavity_n]), .lbo_addr(lb2_addr[cavity_n])
288				    );
289	`else
290	   assign lb2_data[cavity_n] = lb1_data[cavity_n];
291	   assign lb2_addr[cavity_n] = lb1_addr[cavity_n];
292	   assign lb2_write[cavity_n] = lb1_write[cavity_n];
293	   assign collision = 0;
294	`endif
295	
296	   (* lb_automatic, gvar="cavity_n", gcnt=2, cd="lb2", cd_indexed *)
297	   llrf_shell llrf // auto(cavity_n,2) lb2[cavity_n]
298	     (.clk(clk1x),
299	      .a_field(a_field), .a_forward(a_forward), .a_reflect(a_reflect),
300	      .iq(iq), .drive(drive), .piezo_ctl(piezo_ctl),
301	      .iq_recv(17'b0), .qsync_rx(1'b0), .tag_rx(8'b0),
302	      .ext_trig(ext_trig), .master_cic_tick(1'b0),
303	      .mon_result(mon_result), .mon_strobe(mon_strobe), .mon_boundary(mon_boundary),
304	      .slow_op(slow_op), .slow_snap(slow_snap), .slow_out(slow_shell_out),
305	      //.lbi_data(lb2_data), .lbi_addr(lb2_addr), .lbi_write(lb2_write),
306	      `AUTOMATIC_llrf
307	      );
308	
309	   // Setup for clock phasing hack
310	   reg clk1x_div2=0;
311	   always @(posedge clk1x) clk1x_div2 <= ~clk1x_div2;
312	
313	   // Clock phasing hack suggested by Eric, to avoid the old
314	   // (and non-working in Vivado 2020.2) iq2 <= ~clk1x;
315	   // Passes testbench, but still ugly and possibly fragile.
316	   reg clk1x_div2_r=0, clk1x_div2_rr=0;
317	   reg iq2_bogus=0;
318	   always @(posedge clk2x) begin
319	      clk1x_div2_r <= clk1x_div2;  // traditional CDC
320	      clk1x_div2_rr <= clk1x_div2_r;
321	      iq2 <= (clk1x_div2_r ^ clk1x_div2_rr) ? 1'b1 : ~iq2;
322	`ifdef SIMULATE
323	      iq2_bogus <= ~clk1x;
324	`endif
325	   end
326	
327	   // Move iq and drive to clk2x domain unchanged
328	   reg signed [17:0] drive2x=0;
329	   reg iq2x=0;
330	   always @(posedge clk2x) begin
331	      drive2x <= drive;
332	      iq2x <= iq;
333	   end
334	
335	   // Now take care of iq and drive semantics in clk2x domain
336	   reg signed [17:0] drive2_d=0;
337	   reg iq2x_d=0;
338	   always @(posedge clk2x) begin
339	      iq2x_d <= iq2x;
340	      drive2 <= iq2x_d ? drive2x: drive2_d;
341	      drive2_d <= drive2;
342	   end
343	
344	`else
345	   assign simple_demo_flag = 1;
346	   reg simple_iq=0; always @(posedge clk1x) simple_iq <= ~simple_iq;
347	   assign iq=simple_iq;
348	   assign drive=0;
349	   assign mon_result=20'hdead0;
350	   assign mon_strobe=0;
351	   assign mon_boundary=0;
352	   wire [2:0] cbuf_mode=1;  // hard-code simple mode
353	`endif  // SIMPLE_DEMO
354	
355	   reg [15:0] simple_cnt=0;
356	   always @(posedge clk1x) simple_cnt <= buf_sync ? 0 : simple_cnt+1;
357	   wire [15:0] sim_result = simple_cnt;
358	   wire sim_strobe = simple_cnt[3] == 1;
359	   wire sim_boundary = ~sim_strobe;
360	
361	   always @(posedge clk1x) case (cbuf_mode)
362		0: begin buf_data <= mon_result[19:4]; buf_strobe <= mon_strobe; buf_bound <= mon_boundary; end
363		1: begin buf_data <= sim_result; buf_strobe <= sim_strobe; buf_bound <= sim_boundary; end
364		2: begin buf_data <= a_field; buf_strobe <= 1; buf_bound <= 1; end
365		3: begin buf_data <= a_forward; buf_strobe <= 1; buf_bound <= 1; end
366		4: begin buf_data <= a_reflect; buf_strobe <= 1; buf_bound <= 1; end
367		5: begin buf_data <= drive[17:2]; buf_strobe <= 1; buf_bound <= iq; end
368		default: begin buf_data <= 0; buf_strobe <= 0; buf_bound <= 0; end
369	   endcase
370	
371	end endgenerate
372	
373	reg signed [17:0] eig_drive0=0, total_eig_drive=0;
374	wire signed [17:0] noise_eig_drive;
375	wire res_clip;
376	(* lb_automatic, cd="clk2x" *)
377	cav_mech #(.n_mech_modes(n_mech_modes)) cav_mech // auto clk2x
378	  (.clk(clk2x),
379	   .start_eig(start_eig), .noise_eig_drive(noise_eig_drive), .eig_drive(total_eig_drive),
380	   .start_outer(start_outer), .mech_x(mech_x), .res_clip(res_clip),
381	   //.we_prng_iva(we_cav_mech_prng_iva), .we_prng_ivb(we_cav_mech_prng_ivb),
382	   `AUTOMATIC_cav_mech
383	);
384	
385	// Sum these drive terms together
386	reg signed [18:0] local_eig_drive=0;
387	wire signed [19:0] sum_eig_drive = cav_eig_drive_acc[cavity_count] + local_eig_drive;
388	reg edrive_clip=0;
389	always @(posedge clk2x) begin
390	   local_eig_drive <= piezo_eig_drive_acc[cavity_count] + noise_eig_drive;  // pipeline add just like cav_elec.v
391	   eig_drive0 <= `SAT(sum_eig_drive,19,17);
392	   total_eig_drive <= eig_drive0;
393	   edrive_clip <= ~`UNIFORM(sum_eig_drive[19:17]);
394	end
395	
396	// Reserve space for several possible clipping status signals
397	// Caller should take care of latching, reporting, and clearing.
398	assign clips = {6'b0, edrive_clip, res_clip};
399	
400	// Configuration and parameter ROM
401	wire [7:0] rom_data0;
402	parameter use_config_rom = 1; //
403	
404	generate if (use_config_rom == 1)
405	     config_romx rom(.address(lb_addr[4:0]), .data(rom_data0));
406	endgenerate
407	
408	reg [7:0] config_data0=0;
409	always @(lb_addr[4:0]) case(lb_addr[4:0])
410		5'h00: config_data0 = 8'haa;
411		5'h01: config_data0 = circle_aw;
412		5'h02: config_data0 = mode_count;
413		5'h03: config_data0 = mode_shift;
414		5'h04: config_data0 = n_mech_modes;
415		5'h05: config_data0 = df_scale;
416		5'h06: config_data0 = simple_demo_flag;
417		5'h07: config_data0 = cavity_count;
418		default: config_data0 = 0;
419	endcase
420	reg [cavity_count*2+9:0] rom_data=0;  // add two extra padding bits on left to work around Xilinx synthesizer bug
421	integer ix;
422	always @(posedge lb_clk) begin
423		rom_data[7:0] <= lb_addr[5] ? config_data0 : rom_data0;
424		for (ix=0; ix<cavity_count; ix=ix+1)
425			rom_data[9+2*ix +: 2] <= {slow_data_ready[ix], circle_data_ready[ix]};
426	end
427	
428	// This will only get more complex ...
429	//   control register mirror memory
430	//   frequency counter
431	// Configuration has one stage of pipeline circle_buf, slow_bridge, and rom.
432	// One more here, making read_pipe = 2
433	reg [16:0] lb_addr_d1=0;
434	reg [31:0] lb_out_r=0;
435	always @(posedge lb_clk) begin
436		lb_addr_d1 <= lb_addr;
437		// Note: use of mirror_out_0 triggers warnings under newad -y
438		// since it's so tightly coupled to operation of newad.  Actually harmless.
439		lb_out_r <= (lb_addr_d1[16:14] == 3'b101) ? circle_out[lb_addr_d1[13]] :
440			((lb_addr_d1[16:14] == 3'b100) & lb_addr_d1[13]) ? slow_bridge_out[lb_addr_d1[9]] :
441			lb_addr_d1[16] ? rom_data : mirror_out_0;
442	end
443	assign lb_out = lb_out_r;
444	
445	`undef SAT
446	`undef UNIFORM
447	
448	endmodule
449

file.content:
`timescale 1ns / 1ns

`define LB_DECODE_cryomodule

`define AUTOMATIC_decode
`define AUTOMATIC_map
`define AUTOMATIC_beam
`define AUTOMATIC_cavity
`define AUTOMATIC_llrf
`define AUTOMATIC_cav_mech
`define AUTOMATIC_tgen
`include "cryomodule_auto.vh"

// Combination of LLRF controller and cavity emulator.
// Portable Verilog, interfaces to a host via an abstract local bus.

// Three clock domains, with the three clocks passed to this module:
//   lb_clk  e.g., 125 MHz Ethernet
//   clk1x   ADC clock of controller, e.g., 94 MHz for LCLS-2
//   clk2x   double-speed clock used by cavity simulator
// Proper data hand-off between clock domains is handled here.

// In an XC7A part, synthesizes to 18132 LUT, 10 RAMB36E1, 9 RAMB18E1, 51 DSP48E1
// Has some "issues" making reasonable timing in the clk2x domain

// 16-bit (0 to 7fff) address map
// write:
//      0 to 3fff   LLRF controller 1, see llrf_shell.v
//        (use addresses in llrf_shell block of addr_map.vh,
//        and maybe the registers listed in fgen.v and tgen.v)
//   3800           Trigger changeover to next circle_buf_0
//   3801           Trigger changeover to next circle_buf_0
//   4000 to 7fff   LLRF controller 2, see llrf_shell.v
//        (use addresses in llrf_shell block of addr_map.vh,
//        and maybe the registers listed in fgen.v and tgen.v)
//   8000 to ffff   Simulator, see vmod1.v
//        (add 4000 to addresses in vmod1 block of addr_map.vh)
// read:
//  10000 to 1003f   Configuration and parameter ROM, and circle buffer ready flag
//        (see config_romx.v makefile target for bits [7:0]; the ready
//        flag is bit 8)
//  12000 to 121ff   Slow readout, see slow_bridge.v
//        (see slow_larger.list makefile target for the contents)
//  12200 to 123ff   Slow readout, see slow_bridge.v
//        (see slow_larger.list makefile target for the contents)
//  14000 to 15fff   Circular buffer
//        (16-bit signed, usually 8 channels per time step and 1024 time
//        steps, when ch_keep has 8 of 12 bits set)
//  16000 to 17fff   Circular buffer
//        (16-bit signed, usually 8 channels per time step and 1024 time
//        steps, when ch_keep has 8 of 12 bits set)
// Reads are generally passive; the exception is address 5fff, which
// signals that the reading of one buffer is complete so the double-buffer
// logic and flip and make the next one available.

// `define SIMPLE_DEMO  // Used to get a 5-minute bitfile build
module cryomodule(
	input clk1x,
	input clk2x,
	// Local Bus drives both simulator and controller
	// Simulator is in the upper 16K, controller in the lower 16K words.
	input lb_clk,
	input [31:0] lb_data,
	input [16:0] lb_addr,
	input lb_write,  // single-cycle causes a write
	input lb_read,
	output [31:0] lb_out
);
`undef AUTOMATIC_self

// Note that the following five parameters should all be in the range 0 to 255,
// in order to be properly read out via config_data0, below.
parameter circle_aw = 13; // each half of ping-pong buffer is 8K words
// .. but also allows for testing
// The next four parameters are all passed to vmod1
parameter mode_count = 3;  // drives generate loop in cav_elec.v
parameter mode_shift = 9;
parameter n_mech_modes = 7;
parameter df_scale = 9;
parameter cavity_count = 2;
parameter cavity_ln = 1;  // ceil(log2(cavity_count))

wire [31:0] clk1x_data;
wire [16:0] clk1x_addr;
wire clk1x_write;
wire clk1x_clk;
wire [31:0] clk2x_data;
wire [16:0] clk2x_addr;
wire clk2x_write;
wire clk2x_clk, clk;
assign clk2x_clk = clk2x;
assign clk=clk2x;
wire [31:0] lb2_data[0:cavity_count];
wire [16:0] lb2_addr[0:cavity_count];
wire lb2_write[0:cavity_count];

wire [31:0] lb1_data[0:cavity_count];
wire [16:0] lb1_addr[0:cavity_count];
wire lb1_write[0:cavity_count];
wire lb2_clk = clk1x;
`AUTOMATIC_decode
`AUTOMATIC_map
`define SAT(x,old,new) ((~|x[old:new] | &x[old:new]) ? x[new:0] : {x[old],{new{~x[old]}}})
`define UNIFORM(x) ((~|(x)) | &(x))  // All 0's or all 1's

parameter n_cycles = n_mech_modes * 2;
parameter interp_span = 4;  // ceil(log2(n_cycles))
parameter sr_length = 4*8;

`ifndef SIMPLE_DEMO
// Transfer local bus to clk2x domain
data_xdomain #(.size(32+17)) lb_to_2x(
.clk_in(lb_clk), .gate_in(lb_write), .data_in({lb_addr,lb_data}),
.clk_out(clk2x), .gate_out(clk2x_write), .data_out({clk2x_addr,clk2x_data}));
// Transfer local bus to clk1x domain
data_xdomain #(.size(32+17)) lb_to_1x(
.clk_in(lb_clk), .gate_in(lb_write), .data_in({lb_addr,lb_data}),
.clk_out(clk1x), .gate_out(clk1x_write), .data_out({clk1x_addr,clk1x_data}));
`endif // SIMPLE_DEMO

// Create start pulses at configured interval
reg start=0;
reg [7:0] mech_cnt=0;
always @(posedge clk2x) begin
   mech_cnt <= mech_cnt==0 ? n_cycles-1 : mech_cnt-1;
   start <= mech_cnt == 0;
end
wire start_outer;
reg_delay #(.dw(1), .len(0))
	start_outer_g(.clk(clk2x), .reset(1'b0), .gate(1'b1), .din(start), .dout(start_outer));
wire start_eig;
reg_delay #(.dw(1), .len(1))
	start_eig_g(.clk(clk2x), .reset(1'b0), .gate(1'b1), .din(start), .dout(start_eig));

// Arrays for the generate loop
wire signed [17+cavity_ln:0] cav_eig_drive_acc[0:cavity_count];
assign cav_eig_drive_acc[0]=0;
wire signed [17+cavity_ln:0] piezo_eig_drive_acc[0:cavity_count];
assign piezo_eig_drive_acc[0]=0;
wire signed [15:0] circle_out[0:cavity_count];
wire [7:0] slow_bridge_out[0:cavity_count];
wire [cavity_count-1:0]circle_data_ready;
wire [cavity_count-1:0]slow_data_ready;

wire [7:0] clips;  // XXX decide on a way to read this out
wire signed [17:0] mech_x;
wire simple_demo_flag;
// decode this address by hand
reg [2:0] cbuf_mode=0;
// XXX cbuf_mode should really be generated in clk1x domain, but it doesn't
// actually change that often
//always @(posedge lb_clk) if (lb_write & (lb_addr == 554)) cbuf_mode <= lb_data;
always @(posedge lb_clk) if (lb_write & (lb_addr == 17'h1022a)) cbuf_mode <= lb_data;

genvar cavity_n;
generate for (cavity_n=0; cavity_n < cavity_count; cavity_n=cavity_n+1) begin: cryomodule_cavity
   reg signed [17:0] drive2=0; reg iq2=1;  // computed later
   //wire [3:0] beam_timing=0;  // XXX for simulator
   wire signed [17:0] piezo_ctl;  // controller output
   wire signed [15:0] a2_field, a2_forward, a2_reflect;  // simulator output

   reg signed [15:0] a_field=0, a_forward=0, a_reflect=0;
   wire signed [17:0] drive; wire iq;
   // Waveform data from llrf
   wire [19:0] mon_result;
   wire mon_strobe, mon_boundary;
   wire buf_sync; // temporarily route to llrf_shell trig
   reg [15:0] buf_data=0;
   reg buf_strobe=0, buf_bound=0;
`ifndef SIMPLE_DEMO
   // Beam timing generator
   // beam_timing output is limited to [0,phase_step].
   wire [11:0] beam_timing;
   (* lb_automatic, gvar="cavity_n", gcnt=2, cd="clk2x" *)
   beam beam  // auto(cavity_n,2) clk2x
     (.clk(clk2x), .ena(iq), .reset(1'b0), .pulse(beam_timing),
      `AUTOMATIC_beam);
   // Instantiate simulator in clk2x domain
   wire signed [17:0] cav_eig_drive;
   wire signed [17:0] piezo_eig_drive;
   // Parameter settings here should be mirrored in param.py
   // Instantiating the Station module here:
   (* lb_automatic, gvar="cavity_n", gcnt=2, cd="clk2x" *)
   station #(.mode_count(mode_count), .mode_shift(mode_shift), .n_mech_modes(n_mech_modes), .df_scale(df_scale)) cavity // auto(cavity_n,2) clk2x
     (.clk(clk2x),
      .beam_timing(beam_timing), .mech_x(mech_x), .cav_eig_drive(cav_eig_drive),
      .piezo_eig_drive(piezo_eig_drive), .start_outer(start_outer),
      .iq(iq2), .drive(drive2), .start(start), .piezo(piezo_ctl),
      .a_field(a2_field), .a_forward(a2_forward), .a_reflect(a2_reflect),
      // TODO: These `we_*` wires below, are taken from the decode signals that are auto generated
      //.we_prng_iva(we_cavity_0_prng_iva), .we_prng_ivb(we_cavity_0_prng_ivb),
      `AUTOMATIC_cavity
      );

   assign cav_eig_drive_acc[cavity_n+1] = cav_eig_drive_acc[cavity_n] + cav_eig_drive;
   assign piezo_eig_drive_acc[cavity_n+1] = piezo_eig_drive_acc[cavity_n] + piezo_eig_drive;

   // Transfer ADCs to clk1x domain
   always @(posedge clk1x) begin
      a_field <= a2_field;
      a_forward <= a2_forward;
      a_reflect <= a2_reflect;
   end
   // Instantiate circular buffer
   // Reading from 0xfff is magic, says we are done reading a bank
   wire [15:0] circle_count, circle_stat;
   wire circle_stop=0; // not used
   //wire circle_stb = lb_read & lb_addr[14:13]==2'b10;
   wire buf_transferred;

   // 0x4000 to 0x5fff for cavity 0
   // 0x6000 to 0x7fff for cavity 1
   // TODO: To be modified for cavity_count > 2
   wire buf_read = lb_read & (lb_addr[16:14] == 3'b101) & (lb_addr[13]==cavity_n);
   wire buf_flip = lb_write & (lb_addr == (17'h13800 + cavity_n));  // in lb_clk domain
   circle_buf #(.aw(circle_aw), .auto_flip(0)) circle(
	.iclk(clk1x),
	.d_in(buf_data), .stb_in(buf_strobe), .boundary(buf_bound),
	.stop(circle_stop), .buf_sync(buf_sync),
	.buf_transferred(buf_transferred),
	.oclk(lb_clk), .enable(circle_data_ready[cavity_n]),
	.read_addr(lb_addr[circle_aw-1:0]), // .read_strobe(buf_read),
	.d_out(circle_out[cavity_n]), .stb_out(buf_flip),
	.buf_count(circle_count), .buf_stat(circle_stat));

   // Bridge slow readout subsystem to the local bus
   wire slow_op, slow_invalid;
   reg slow_snap=0; always @(posedge clk1x) slow_snap<=buf_sync;
   wire [7:0] slow_out;
   // 0x2000 to 0x21ff for cavity 0
   // 0x2200 to 0x23ff for cavity 1
   // Should be good up to 16 cavities
   wire lb_slow_read = lb_read & (lb_addr[16:9] == 'b10010000 + cavity_n);
   slow_bridge slow_bridge(.lb_clk(lb_clk), .lb_addr(lb_addr[14:0]),
			   .lb_read(lb_slow_read), .lb_out(slow_bridge_out[cavity_n]),
			   .invalid(slow_invalid),
			   .slow_clk(clk1x), .slow_op(slow_op), .slow_snap(buf_transferred),
			   .slow_out(slow_out));
   assign slow_data_ready[cavity_n] = circle_data_ready[cavity_n] & ~slow_invalid;  // XXX mixes domains, simulate to make sure it's glitch-free
   // Make our own additions to slow shift register
   // equivalence circle_stat: circle_fault 1, circle_wrap 1, circle_addr 14
   wire [sr_length-1:0] slow_sr_data = { circle_count, circle_stat };
   // TODO: These `we_*` wires below, are taken from the decode signals that are auto generated
   wire [7:0] slow_shell_out;

   reg [sr_length-1:0] slow_read=0;
   always @(posedge clk1x) if (slow_op) begin
      slow_read <= slow_snap ? slow_sr_data : {slow_read[sr_length-9:0],slow_shell_out};
   end
   assign slow_out = slow_read[sr_length-1:sr_length-8];

   assign simple_demo_flag = 0;
   // Instantiate controller in clk domain
   wire ext_trig=buf_sync;


   // Timing generator, interposes on local bus
   wire collision, collision1;

`define USE_TGEN
`ifdef USE_TGEN
   (* lb_automatic, gvar="cavity_n", gcnt=2, cd="lb2", cd_indexed *)
   tgen tgen // auto(cavity_n,2) lb2[cavity_n]
     (.clk(clk1x), .trig(ext_trig), .collision(collision1),
      .lb_data(clk1x_data), .lb_write(clk1x_write), .lb_addr(clk1x_addr),
      .addr_padding(1'b0),
      .lbo_data(lb1_data[cavity_n]), .lbo_write(lb1_write[cavity_n]), .lbo_addr(lb1_addr[cavity_n]),
      // TODO: This is hard-coded to the tgen_0
      // .delay_pc_addr_hit(`ADDR_HIT_tgen_0_delay_pc_XXX & (cavity_n == 0)),
      // Note: use of we_tgen_0_delay_pc_XXX triggers warnings under newad -y
      // since it's so tightly coupled to operation of newad.  Actually harmless.
      .dests_write(we_tgen_0_delay_pc_XXX & (cavity_n == 0)),
      `AUTOMATIC_tgen
      );
`else
   assign lb1_data[cavity_n] = clk1x_data;
   assign lb1_addr[cavity_n] = clk1x_addr;
   assign lb1_write[cavity_n] = clk1x_write;
   assign collision1 = 0;
`endif

   // Function generator, interposes on local bus
   //`define USE_FGEN
`ifdef USE_FGEN
   fgen #(.addr_hi(0)) fgen(.clk(clk1x), .trig(ext_trig), .collision(collision),
			    .lb_data(lb1_data[cavity_n]), .lb_write(lb1_write[cavity_n]), .lb_addr(lb1_addr[cavity_n]),
			    .lbo_data(lb2_data[cavity_n]), .lbo_write(lb2_write[cavity_n]), .lbo_addr(lb2_addr[cavity_n])
			    );
`else
   assign lb2_data[cavity_n] = lb1_data[cavity_n];
   assign lb2_addr[cavity_n] = lb1_addr[cavity_n];
   assign lb2_write[cavity_n] = lb1_write[cavity_n];
   assign collision = 0;
`endif

   (* lb_automatic, gvar="cavity_n", gcnt=2, cd="lb2", cd_indexed *)
   llrf_shell llrf // auto(cavity_n,2) lb2[cavity_n]
     (.clk(clk1x),
      .a_field(a_field), .a_forward(a_forward), .a_reflect(a_reflect),
      .iq(iq), .drive(drive), .piezo_ctl(piezo_ctl),
      .iq_recv(17'b0), .qsync_rx(1'b0), .tag_rx(8'b0),
      .ext_trig(ext_trig), .master_cic_tick(1'b0),
      .mon_result(mon_result), .mon_strobe(mon_strobe), .mon_boundary(mon_boundary),
      .slow_op(slow_op), .slow_snap(slow_snap), .slow_out(slow_shell_out),
      //.lbi_data(lb2_data), .lbi_addr(lb2_addr), .lbi_write(lb2_write),
      `AUTOMATIC_llrf
      );

   // Setup for clock phasing hack
   reg clk1x_div2=0;
   always @(posedge clk1x) clk1x_div2 <= ~clk1x_div2;

   // Clock phasing hack suggested by Eric, to avoid the old
   // (and non-working in Vivado 2020.2) iq2 <= ~clk1x;
   // Passes testbench, but still ugly and possibly fragile.
   reg clk1x_div2_r=0, clk1x_div2_rr=0;
   reg iq2_bogus=0;
   always @(posedge clk2x) begin
      clk1x_div2_r <= clk1x_div2;  // traditional CDC
      clk1x_div2_rr <= clk1x_div2_r;
      iq2 <= (clk1x_div2_r ^ clk1x_div2_rr) ? 1'b1 : ~iq2;
`ifdef SIMULATE
      iq2_bogus <= ~clk1x;
`endif
   end

   // Move iq and drive to clk2x domain unchanged
   reg signed [17:0] drive2x=0;
   reg iq2x=0;
   always @(posedge clk2x) begin
      drive2x <= drive;
      iq2x <= iq;
   end

   // Now take care of iq and drive semantics in clk2x domain
   reg signed [17:0] drive2_d=0;
   reg iq2x_d=0;
   always @(posedge clk2x) begin
      iq2x_d <= iq2x;
      drive2 <= iq2x_d ? drive2x: drive2_d;
      drive2_d <= drive2;
   end

`else
   assign simple_demo_flag = 1;
   reg simple_iq=0; always @(posedge clk1x) simple_iq <= ~simple_iq;
   assign iq=simple_iq;
   assign drive=0;
   assign mon_result=20'hdead0;
   assign mon_strobe=0;
   assign mon_boundary=0;
   wire [2:0] cbuf_mode=1;  // hard-code simple mode
`endif  // SIMPLE_DEMO

   reg [15:0] simple_cnt=0;
   always @(posedge clk1x) simple_cnt <= buf_sync ? 0 : simple_cnt+1;
   wire [15:0] sim_result = simple_cnt;
   wire sim_strobe = simple_cnt[3] == 1;
   wire sim_boundary = ~sim_strobe;

   always @(posedge clk1x) case (cbuf_mode)
	0: begin buf_data <= mon_result[19:4]; buf_strobe <= mon_strobe; buf_bound <= mon_boundary; end
	1: begin buf_data <= sim_result; buf_strobe <= sim_strobe; buf_bound <= sim_boundary; end
	2: begin buf_data <= a_field; buf_strobe <= 1; buf_bound <= 1; end
	3: begin buf_data <= a_forward; buf_strobe <= 1; buf_bound <= 1; end
	4: begin buf_data <= a_reflect; buf_strobe <= 1; buf_bound <= 1; end
	5: begin buf_data <= drive[17:2]; buf_strobe <= 1; buf_bound <= iq; end
	default: begin buf_data <= 0; buf_strobe <= 0; buf_bound <= 0; end
   endcase

end endgenerate

reg signed [17:0] eig_drive0=0, total_eig_drive=0;
wire signed [17:0] noise_eig_drive;
wire res_clip;
(* lb_automatic, cd="clk2x" *)
cav_mech #(.n_mech_modes(n_mech_modes)) cav_mech // auto clk2x
  (.clk(clk2x),
   .start_eig(start_eig), .noise_eig_drive(noise_eig_drive), .eig_drive(total_eig_drive),
   .start_outer(start_outer), .mech_x(mech_x), .res_clip(res_clip),
   //.we_prng_iva(we_cav_mech_prng_iva), .we_prng_ivb(we_cav_mech_prng_ivb),
   `AUTOMATIC_cav_mech
);

// Sum these drive terms together
reg signed [18:0] local_eig_drive=0;
wire signed [19:0] sum_eig_drive = cav_eig_drive_acc[cavity_count] + local_eig_drive;
reg edrive_clip=0;
always @(posedge clk2x) begin
   local_eig_drive <= piezo_eig_drive_acc[cavity_count] + noise_eig_drive;  // pipeline add just like cav_elec.v
   eig_drive0 <= `SAT(sum_eig_drive,19,17);
   total_eig_drive <= eig_drive0;
   edrive_clip <= ~`UNIFORM(sum_eig_drive[19:17]);
end

// Reserve space for several possible clipping status signals
// Caller should take care of latching, reporting, and clearing.
assign clips = {6'b0, edrive_clip, res_clip};

// Configuration and parameter ROM
wire [7:0] rom_data0;
parameter use_config_rom = 1; //

generate if (use_config_rom == 1)
     config_romx rom(.address(lb_addr[4:0]), .data(rom_data0));
endgenerate

reg [7:0] config_data0=0;
always @(lb_addr[4:0]) case(lb_addr[4:0])
	5'h00: config_data0 = 8'haa;
	5'h01: config_data0 = circle_aw;
	5'h02: config_data0 = mode_count;
	5'h03: config_data0 = mode_shift;
	5'h04: config_data0 = n_mech_modes;
	5'h05: config_data0 = df_scale;
	5'h06: config_data0 = simple_demo_flag;
	5'h07: config_data0 = cavity_count;
	default: config_data0 = 0;
endcase
reg [cavity_count*2+9:0] rom_data=0;  // add two extra padding bits on left to work around Xilinx synthesizer bug
integer ix;
always @(posedge lb_clk) begin
	rom_data[7:0] <= lb_addr[5] ? config_data0 : rom_data0;
	for (ix=0; ix<cavity_count; ix=ix+1)
		rom_data[9+2*ix +: 2] <= {slow_data_ready[ix], circle_data_ready[ix]};
end

// This will only get more complex ...
//   control register mirror memory
//   frequency counter
// Configuration has one stage of pipeline circle_buf, slow_bridge, and rom.
// One more here, making read_pipe = 2
reg [16:0] lb_addr_d1=0;
reg [31:0] lb_out_r=0;
always @(posedge lb_clk) begin
	lb_addr_d1 <= lb_addr;
	// Note: use of mirror_out_0 triggers warnings under newad -y
	// since it's so tightly coupled to operation of newad.  Actually harmless.
	lb_out_r <= (lb_addr_d1[16:14] == 3'b101) ? circle_out[lb_addr_d1[13]] :
		((lb_addr_d1[16:14] == 3'b100) & lb_addr_d1[13]) ? slow_bridge_out[lb_addr_d1[9]] :
		lb_addr_d1[16] ? rom_data : mirror_out_0;
end
assign lb_out = lb_out_r;

`undef SAT
`undef UNIFORM

endmodule

`timescale 1ns / 1ns

// XXX Still under construction
// Larry Doolittle, LBNL, August 2014
// see llrf_shell.v
`define AUTOMATIC_self
`define AUTOMATIC_decode
`define AUTOMATIC_lp_notch
`define AUTOMATIC_fdbk_core
`define AUTOMATIC_piezo
`include "rf_controller_auto.vh"

// lb_addr supports at least 4K words; see piezo_control.v for explanation why.
module rf_controller (
	// Everything here is in one clock domain, matches ADC
	input clk,

	// RF ADC inputs, at IF
	input signed [15:0] a_field,
	input signed [15:0] a_forward,
	input signed [15:0] a_reflect,
	input signed [15:0] a_phref,
	// RF ADC inputs from fiber link
	input [16:0] iq_recv,
	input qsync_rx,
	// RF drive without local upconversion
	output iq,
	output signed [17:0] drive,
	// SSB RF DAC drive (if you don't use it, six multipliers will disappear)
	output signed [15:0] dac1_out0,
	output signed [15:0] dac1_out1,
	output signed [15:0] dac2_out0,
	output signed [15:0] dac2_out1,
	// Piezo interface
	output signed [17:0] piezo_ctl,
	output piezo_stb,
	// Digaree monitoring capability
	output [6:0] sat_count,
	output trace_boundary,
	output signed [23:0] trace_out,
	output trace_out_gate,
	// External trigger capability (not sure how useful this will be)
	input ext_trig,
	input master_cic_tick,
	// See comments in llrf_shell.v
	output [7:0] tag_now,
	// See comments in mp_proc.v
	output [11:0] cmp_event,
	// External waveform recording
	output signed [19:0] mon_result,
	output mon_strobe,
	output mon_boundary,
	// host-writable control registers
	(* external *)
	input [31:0] phase_step,  // external
	(* external *)
	input [11:0] modulo,  // external
	(* external, signal_type="single-cycle" *)
	input ctlr_ph_reset,  // external single-cycle
	(* external *)
	input [7:0] wave_samp_per,  // external
	(* external *)
	input [11:0] chan_keep,  // external
	(* external *)
	input [2:0] wave_shift,  // external
	(* external *)
	input [1:0] use_fiber_iq,  // external
	(* external *)
	input [7:0] tag, // external
	`AUTOMATIC_self
);
`undef AUTOMATIC_self

`AUTOMATIC_decode

parameter cic_base_period = 33;  // nominal LCLS-II IF = clk * 7/33

// Brain-dead functionality here, just routing from host-writable register
// to llrf_shell-readable port.
assign tag_now = tag;

// DDS
wire [19:0] phase_step_h = phase_step[31:12];
wire [11:0] phase_step_l = phase_step[11:0];
wire signed [17:0] cosa, sina;
// floor(2^17*(32/33)^2/1.646760258-3) = 74840
// parameter [17:0] lo_amp = 74840;
// Now divide by abs(1+i/16) to keep second_if_out happy
// Other users of cosa,sina will need to account for that 0.2% cal change
parameter [17:0] lo_amp = 74694;
reg dds_reset=0;
rot_dds #(.lo_amp(lo_amp)) dds(.clk(clk), .reset(dds_reset),
	.cosa(cosa), .sina(sina),
	.phase_step_h(phase_step_h), .phase_step_l(phase_step_l),
	.modulo(modulo)
);

// Tricky stuff to allow DDS to go back to a known phase after messing with its frequency
// dds_reset gets a single-cycle hit based on master_cic_tick when requested from software
reg dds_reset_req=0;
always @(posedge clk) begin
	dds_reset <= master_cic_tick & dds_reset_req;
	if (master_cic_tick) dds_reset_req <= 0;
	if (ctlr_ph_reset) dds_reset_req <= 1;
end

// Boost amplitude of LO for use in upconverter and (postponed) fdownconvert,
// since those use cases don't have an internal gain of (33/32)^2.
// Resulting LO has amplitude 74762*1.646760258/2^17*(17/16) = 0.99800
reg signed [17:0] cosal=0, sinal=0;
always @(posedge clk) begin
	cosal <= cosa + (cosa >>> 4);
	sinal <= sina + (sina >>> 4);
end

// State divider
reg [2:0] state=0;
wire state_reset = qsync_rx & use_fiber_iq[0];
// Interchanging I and Q changes handedness of coordinate system;
// sync_state of 2 tested good on hardware in BEG lab, but leave a hook
// in case something changes.
wire [2:0] sync_state = use_fiber_iq[1] ? 1 : 2;
always @(posedge clk) state <= state_reset ? sync_state : state+1;
assign iq=state[0];
reg sync=0;
always @(posedge clk) sync <= state==6;

// CIC timing, LCLS-II configuration supporting 7/33
reg [5:0] cic_state=0;
reg cic_sample=0;
reg [7:0] wave_cnt=0;
always @(posedge clk) begin
	cic_state <= cic_state==(cic_base_period-1) ? 0 : cic_state+1;
	cic_sample <= cic_state==0;
	if (cic_sample) wave_cnt <= wave_cnt==1 ? wave_samp_per : wave_cnt-1;
end
wire sample_wave = wave_cnt==1;

// Multi-channel radio
// Note that we no longer look at phref
wire [43:0] sr_out;
wire sr_valid;
cim_12x #(.dw(44)) cim(.clk(clk), .reset(1'b0), .sample(cic_sample),
	.adca(a_field), .adcb(a_forward), .adcc(a_reflect),
	.inm(iq_recv[16:1]), .outm(drive[17:2]), .iqs(~iq),
	.adcx(16'b0),  // not much point to use this unless we set up a second DDS
	.cosa(cosa), .sina(sina),
	.cosb(18'b0), .sinb(18'b0),
	.sr_out(sr_out), .sr_valid(sr_valid)
);
wire [39:0] sr_out_trunc = sr_out[43:4];  // Truncate truncated and you get trunc

// Process radios for waveform monitoring
wire signed [19:0] mon_12_result;
wire mon_12_strobe;
ccfilt #(.dw(40), .dsr_len(12), .shift_base(4)) ccfilt(.clk(clk),
	.sr_in(sr_out_trunc), .sr_valid(sr_valid & sample_wave),
	.shift({wave_shift,1'b1}), .reset(1'b0),
	.result(mon_12_result), .strobe(mon_12_strobe)
);

fchan_subset #(.a_dw(20), .o_dw(20), .len(12)) fchan_subset(
	.clk(clk), .keep(chan_keep), .reset(1'b0),
	.a_data(mon_12_result), .a_gate(mon_12_strobe), .a_trig(~mon_12_strobe),
	.o_data(mon_result), .o_gate(mon_strobe), .o_trig(mon_boundary)
);

// Process radios for (simple) piezo loop
(* lb_automatic *)
piezo_control piezo // auto
	(.clk(clk),
	.sr_in(sr_out_trunc[35:0]), .sr_valid(sr_valid),
	.piezo_ctl(piezo_ctl), // .piezo_stb(piezo_stb),
	.sat_count(sat_count), .piezo_stb(trace_boundary),
	.trace_out(trace_out), .trace_out_gate(trace_out_gate),
	`AUTOMATIC_piezo
);
assign piezo_stb = cic_sample; // one in 33?

// Washout filter
wire signed [15:0] b_field;
fwashout washout(.clk(clk), .rst(1'b0), .track(1'b1),
	.a_data(a_field), .a_gate(1'b1), .a_trig(1'b0),
	.o_data(b_field)
);

// Digital downconverter
wire signed [15:0] field_xy;
fdownconvert down(.clk(clk), .mod2(iq),
	.cosd(cosa), .sind(sina),  // LO signals
	.a_data(b_field), .o_data(field_xy),
	.a_gate(1'b1), .a_trig(1'b0)  // not really used
);

// Feedback loop core
// Select input source: local ADC or remote over fiber
wire signed [17:0] fdbk_in = use_fiber_iq[0] ? {iq_recv,1'b0} : {field_xy,2'b0};
// iq flag is synchronized via state_reset above
wire signed [17:0] fdbk_out_xy;
(* lb_automatic *)
fdbk_core fdbk_core  // auto
	(.clk(clk),
	.sync(sync),
	.iq(iq), .in_xy(fdbk_in), .out_xy(fdbk_out_xy), .cmp_event(cmp_event),
	// unused features
	.chirp_en(1'b0), .chirp_amp(18'b0), .chirp_ph(19'b0),
	.ffd_en(1'b0), .ff_setm(18'b0), .ff_setp(18'b0), .ff_ddrive(18'b0), .ff_dphase(18'b0),
	.ffp_en(1'b0), .ff_drive(18'b0), .ff_phase(18'b0),
	//
	`AUTOMATIC_fdbk_core
);

// Output low-pass and notch filter combo
wire signed [19:0] drive_w;
(* lb_automatic *)
lp_notch lp_notch  // auto
	(.clk(clk), .iq(iq),
	.x(fdbk_out_xy), .y(drive_w),
	`AUTOMATIC_lp_notch
);
assign drive = drive_w[19:2];

// second_if_out and ssb_out are pin-compatible
second_if_out upconvert(.clk(clk),
	.div_state(state[1:0]), .drive(drive),
	.enable(1'b1), .lo_sel(1'b0),
	.cosa(cosal), .sina(sinal),
	.dac1_out0(dac1_out0), .dac1_out1(dac1_out1),
	.dac2_out0(dac2_out0), .dac2_out1(dac2_out1)
);

endmodule

`timescale 1ns / 1ns

module slow_bridge(
	// 32-bit local bus (slave)
	input lb_clk,
	input [14:0] lb_addr,
	input lb_read,
	output [7:0] lb_out,
	// Output status bit, valid in slow_clk domain
	output invalid,   // indicates internal data transfer in progress
	// 8-bit shift-register port (master)
	input slow_clk,
	output slow_op,
	input slow_snap,
	input [7:0] slow_out
);

reg running=0, shifting=0;
reg [8:0] write_addr=0;
always @(posedge slow_clk) begin
	if (slow_snap | &write_addr) running <= slow_snap;
	if (running) write_addr <= write_addr+1;
	shifting <= running & |write_addr[8:4];
end

wire [7:0] ram_out;
dpram #(.aw(9), .dw(8)) ram(.clka(slow_clk), .clkb(lb_clk),
	.addra(write_addr), .dina(slow_out), .wena(running),
	.addrb(lb_addr[8:0]), .doutb(ram_out));

assign lb_out = ram_out;  // pad from 8 to 32 bits?
assign slow_op = slow_snap | shifting;
assign invalid = running;

endmodule

`timescale 1ns / 1ns

`include "piezo_control_auto.vh"

module piezo_control(
	input clk,
	input [35:0] sr_in,
	input sr_valid,
	output [17:0] piezo_ctl,
	output piezo_stb,
	output [6:0] sat_count,
	output signed [23:0] trace_out,
	output trace_out_gate,   // use piezo_stb for boundary
	(* external *)
	input [15:0] piezo_dc,  // external
	(* external *)
	input [19:0] sf_consts,  // external
	(* external *)
	output [2:0] sf_consts_addr,  // external
	(* external *)
	input [0:0] trace_en,  // external
	(* external *)
	output [6:0] trace_en_addr  // external address for trace_en
	//`AUTOMATIC_self
);
`undef AUTOMATIC_self

// Non-zero placeholder
// Eventually intend to use reg_mac2 or similar;
// that code takes 2K address space, and we need a bit more
// locally for interfacing (see apex2/lqg_loop1.v).

assign piezo_stb = 1;
assign piezo_ctl = {piezo_dc, 2'b0};
assign sat_count = 0;
assign trace_out = 0;
assign trace_out_gate = 0;
assign sf_consts_addr = 0;
assign trace_en_addr = 0;

endmodule

`timescale 1ns / 1ns

// Additional logic in the main CONTROLLER clock domain that wraps around
// the LLRF controller proper:
//   timing generator
//   function generator
//   slow (byte-serial) readout chain, including ADC min/max values
// Larry Doolittle, LBNL, August 2014
// In Artix under XST 14.7, synthesizes to 6504 LUTs, 20 DSP48E1,
// and clocks at well over 125 MHz.

// always need this
//`define LB_DECODE_llrf_shell
`define AUTOMATIC_self
`define AUTOMATIC_decode
`define AUTOMATIC_controller

`include "llrf_shell_auto.vh"

module llrf_shell(
	input clk,
	// RF ADC inputs, at IF
	input signed [15:0] a_field,
	input signed [15:0] a_forward,
	input signed [15:0] a_reflect,
	// RF DAC drive, but don't upconvert ourselves
	output iq,
	output [17:0] drive,
	// RF ADC inputs from fiber link
	input [16:0] iq_recv,
	input qsync_rx,
	input [7:0] tag_rx,  // XXX add this to slow chain!
	// SSB RF DAC drive (if you don't use it, six multipliers will disappear)
	output [15:0] dac1_out0,
	output [15:0] dac1_out1,
	// Piezo interface
	output signed [17:0] piezo_ctl,
	output piezo_stb,
	// Digaree monitoring capability
	output [6:0] sat_count,
	output trace_boundary,
	output signed [23:0] trace_out,
	output trace_out_gate,
	// External trigger capability (not sure how useful this will be)
	input ext_trig,
	input master_cic_tick,
	// External waveform recording
	output signed [19:0] mon_result,
	output mon_strobe,
	output mon_boundary,
	// Stream of slow data: timestamp and adc min/max for now
	// Keep data path narrow for routing reasons, not logic element count
	input slow_op,
	input slow_snap,
	output [7:0] slow_out,

	`AUTOMATIC_self
);
`undef AUTOMATIC_self

`AUTOMATIC_decode

// Compute raw ADC min/max
wire mm_snap=slow_snap;
wire signed [15:0] adc1_min, adc1_max;
wire signed [15:0] adc2_min, adc2_max;
wire signed [15:0] adc3_min, adc3_max;
minmax #(16) mm1(.clk(clk), .xin(a_field),   .reset(mm_snap), .xmin(adc1_min), .xmax(adc1_max));
minmax #(16) mm2(.clk(clk), .xin(a_forward), .reset(mm_snap), .xmin(adc2_min), .xmax(adc2_max));
minmax #(16) mm3(.clk(clk), .xin(a_reflect), .reset(mm_snap), .xmin(adc3_min), .xmax(adc3_max));

// Nest to get the real work
wire [7:0] tag_now;
wire [11:0] cmp_event;
(* lb_automatic *)
rf_controller controller // auto
	(.clk(clk),
	.a_field(a_field), .a_forward(a_forward), .a_reflect(a_reflect), .a_phref(16'b0),
	.iq_recv(iq_recv), .qsync_rx(qsync_rx),
	.iq(iq), .drive(drive),
	.dac1_out0(dac1_out0), .dac1_out1(dac1_out1),
	.piezo_ctl(piezo_ctl), .piezo_stb(piezo_stb),
	.sat_count(sat_count), .trace_boundary(trace_boundary),
	.trace_out(trace_out), .trace_out_gate(trace_out_gate),
	.ext_trig(ext_trig), .master_cic_tick(master_cic_tick),
	.mon_result(mon_result), .mon_strobe(mon_strobe), .mon_boundary(mon_boundary),
	.tag_now(tag_now), .cmp_event(cmp_event),
	`AUTOMATIC_controller
);

// Logic for controller_status involves latching signals from cmp_event
// Similar synchronous-to-waveform concept as ADC min/max, above
reg [15:0] controller_status=0;
always @(posedge clk) controller_status <= (slow_snap ? 12'b0 : controller_status) | {4'b0, cmp_event};

// Cycle counter
wire [7:0] timestamp_out;
timestamp ts(.clk(clk), .aux_trig(1'b0), .slow_op(slow_op), .slow_snap(slow_snap),
	.shift_in(8'b0), .shift_out(timestamp_out)
);

// Our share of slow readout
// tag_now and tag_old are set up for causality and consistency detection when
// changing other controls. tag_now shows the value of tag at the end-time of
// the buffer, tag_old shows it at the begin-time of the buffer.  Not perfect
// because of non-boxcar filtering and sloppy pipelining.
reg [7:0] tag_old=0;
parameter sr_length = 7*16;
wire [sr_length-1:0] slow_sr_data = { adc1_min, adc1_max, adc2_min, adc2_max, adc3_min, adc3_max, tag_now, tag_old };
reg [sr_length-1:0] slow_read=0;
always @(posedge clk) if (slow_op) begin
	slow_read <= slow_snap ? slow_sr_data : {slow_read[sr_length-9:0],timestamp_out};
	if (slow_snap) tag_old <= tag_now;
end
assign slow_out = slow_read[sr_length-1:sr_length-8];

endmodule

